const webhookData = $('Webhook').first().json.body;
const message = (webhookData.message || '').trim();
const logId = $('Log Inquiry').first().json.id;
const threadTs = webhookData.thread_ts || '';

const thankPatterns = [/^(ありがとう|有難う|感謝|サンクス|thanks|thank you)/i, /^(了解|りょうかい|わかりました|承知|ok|オッケー)/i];
for (const p of thankPatterns) {
  if (p.test(message)) {
    return { json: { skipAgent: true, message, logId, threadTs, responseText: '👍 ご連絡ありがとうございます。他にご質問があればお気軽にどうぞ！' } };
  }
}
return { json: { skipAgent: false, message, logId, threadTs } };

const webhookData = $('Webhook').first().json.body;
const historyRows = $('Fetch Conversation History').all();
const currentMessage = webhookData.message;
const messages = [];
function sanitizeText(text) { if (!text) return ''; return String(text).replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n'); }
for (const row of historyRows) {
  if (row.json.log_type === 'INQUIRY') { messages.push({ role: 'user', content: [{ type: 'text', text: sanitizeText(row.json.message) }] }); }
  else if (row.json.log_type === 'AI_RESPONSE' && row.json.ai_response_text) { messages.push({ role: 'assistant', content: [{ type: 'text', text: sanitizeText(row.json.ai_response_text) }] }); }
}
messages.push({ role: 'user', content: [{ type: 'text', text: sanitizeText(currentMessage) }] });
const payload = JSON.stringify({ messages });
return { json: { messages, messageCount: messages.length, isMultiTurn: messages.length > 1, agentPayload: payload.replace(/'/g, "''") } };

const response = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const logId = $('Log Inquiry').first().json.id;
const messageInfo = $('Build Messages').first().json;
try {
  const agentResponse = JSON.parse(response.RESPONSE || response.response || '{}');
  const contentArray = agentResponse.content || [];
  const textContent = contentArray.find(c => c.type === 'text');
  const content = textContent?.text || '';
  let aiResponseText = content;
  const jsonMatch = content.match(/```json\s*([\s\S]*?)```/);
  if (jsonMatch) { aiResponseText = content.split('```').pop()?.trim().replace(/^[-\s]+/, '') || content; }
  return { json: { inquiry_log_id: logId, user_id: webhookData.user_id, channel_id: webhookData.channel_id, thread_ts: webhookData.thread_ts || '', original_message: webhookData.message || '', category: 'IT', priority: 'MEDIUM', summary: (webhookData.message || '').substring(0, 100), ai_response_text: aiResponseText, turn_number: messageInfo.messageCount, is_multi_turn: messageInfo.isMultiTurn } };
} catch (e) { return { json: { inquiry_log_id: logId, user_id: webhookData.user_id, channel_id: webhookData.channel_id, thread_ts: webhookData.thread_ts || '', original_message: webhookData.message || '', category: 'IT', priority: 'MEDIUM', summary: 'Error', ai_response_text: 'エラーが発生しました。担当者に連絡します。', turn_number: 1, is_multi_turn: false } }; }

