={{ (function() {
  const turnNumber = $('Parse Agent Response').first().json.turn_number || 1;
  const isFirstTurn = turnNumber === 1;
  let aiText = ($('Parse Agent Response').first().json.ai_response_text || '').substring(0, 2900);
  aiText = aiText.replace(/\\n/g, '\n').replace(/\"/g, '"');
  const logId = $('Log AI Response').first().json.id;
  const ticketId = $json.ticket_id;
  const category = $('Parse Agent Response').first().json.category;
  const priority = $('Parse Agent Response').first().json.priority;
  const channelId = $('Parse Agent Response').first().json.channel_id;
  const threadTs = $('Parse Agent Response').first().json.thread_ts;

  const blocks = [
    { type: 'section', text: { type: 'mrkdwn', text: ':robot_face: *IT AI回答*' } },
    { type: 'section', text: { type: 'mrkdwn', text: aiText } },
    { type: 'divider' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: ':ticket: チケット: `' + ticketId + '` | :label: ' + category + ' | :zap: ' + priority }] },
    { type: 'section', text: { type: 'mrkdwn', text: 'この回答は役に立ちましたか？' } }
  ];

  const actionElements = [
    { type: 'button', text: { type: 'plain_text', text: '✅ 解決しました' }, style: 'primary', action_id: 'resolved', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'it' }) }
  ];
  if (isFirstTurn) {
    actionElements.push({ type: 'button', text: { type: 'plain_text', text: '🚨 エスカレーション' }, style: 'danger', action_id: 'escalate', value: JSON.stringify({ log_id: logId, ticket_id: ticketId, category: 'it' }) });
  }
  blocks.push({ type: 'actions', block_id: 'it_feedback_' + logId, elements: actionElements });

  return JSON.stringify({ channel: channelId, thread_ts: threadTs, text: 'AI回答', blocks: blocks });
})() }}
